sql:
SELECT DISTINCT u.user_name
FROM users u
WHERE u.user_id IN (
  SELECT modified_by
  FROM video_versions
) AND u.user_id IN (
  SELECT user_id
  FROM video_access_logs
  WHERE access_type = 'view'
);

